import{_ as a,o as c,c as o,a0 as t}from"./chunks/framework.DgPozsi0.js";const u=JSON.parse('{"title":"[React官網] React 19.2 教程","description":"","frontmatter":{"title":"[React官網] React 19.2 教程"},"headers":[],"relativePath":"pages/f2e/docReact/reactDev/02/reactDev_02_03.md","filePath":"pages/f2e/docReact/reactDev/02/reactDev_02_03.md"}'),d={name:"pages/f2e/docReact/reactDev/02/reactDev_02_03.md"};function i(r,e,l,p,s,n){return c(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="將-react-新增至現有專案中" tabindex="-1">將 React 新增至現有專案中 <a class="header-anchor" href="#將-react-新增至現有專案中" aria-label="Permalink to &quot;將 React 新增至現有專案中&quot;">​</a></h1><p>如果想對現有項目添加一些交互，不必使用 <code>React</code> 將其整個重寫。只需將 <code>React</code> 添加到已有技術棧中，就可以在任何位置渲染交互式的 <code>React</code> 組件。</p><div class="info custom-block"><p class="custom-block-title">本地開發必備</p><ul><li>你需要安裝 <a href="https://nodejs.org/zh-cn/" target="_blank" rel="noreferrer">Node.js</a> 以進行本地開發。雖然可以使用線上演練場或簡單的 <code>HTML</code> 頁面來嘗試 <code>React</code>，但實際上大多數用於開發的 <code>JavaScript</code> 工具都需要 <code>Node.js</code>。</li></ul></div><h2 id="在現有網站的子路由中使用-react" tabindex="-1">在現有網站的子路由中使用 React <a class="header-anchor" href="#在現有網站的子路由中使用-react" aria-label="Permalink to &quot;在現有網站的子路由中使用 React&quot;">​</a></h2><p>假設你在 <code>example.com</code> 部署了一個使用其他服務端技術（如 <code>Rails</code>）構建的應用，但想在 <code>example.com/some-app/</code> 部署一個 <code>React</code> 項目。</p><ul><li><p>推薦的配置方式如下：</p><ol><li><p>使用一個 <a href="/vitepress-study/pages/f2e/docReact/reactDev/02/reactDev_02_01.html">基於 React 的框架</a> 構建應用的 <code>React</code> 部分。</p></li><li><p>在框架配置中將 <code>/some-app</code> 指定為基本路徑（<code>basePath</code> 或 <code>path-prefix</code>）（例如 <code>Next.js</code> 與 <code>Gatsby</code> 皆提供此配置）。</p></li><li><p>配置服務器或代理，以便所有位於 <code>/some-app/</code> 下的請求都由該 <code>React</code> 應用處理。</p></li></ol></li><li><h4 id="特點" tabindex="-1">特點 <a class="header-anchor" href="#特點" aria-label="Permalink to &quot;特點&quot;">​</a></h4><p>這能確保應用的 <code>React</code> 部分受益於框架內置的最佳實踐。即使無法或不想在服務器上運行 <code>JavaScript</code>，也可以使用相同的方法，將靜態導出的 HTML/CSS/JS (<code>Next.js</code> 的<code>next export output</code>，<code>Gatsby</code> 的 <code>default</code>) 替換至 /<code>some-app/</code> 目錄。</p></li></ul><h2 id="在現有頁面的一部分中使用react" tabindex="-1">在現有頁面的一部分中使用React <a class="header-anchor" href="#在現有頁面的一部分中使用react" aria-label="Permalink to &quot;在現有頁面的一部分中使用React&quot;">​</a></h2><p>假設有一個由其他技術堆疊（無論是 <code>Rails</code> 等服務端技術，還是 <code>Backbone</code> 等客戶端技術）構建的現有頁面，並想要在該頁面的某個位置渲染交互式的 <code>React</code> 組件（這正是 <code>Meta</code> 多年來使用 <code>React</code> 的常見方式）。</p><ul><li>整合可以分兩步進行： <ul><li><h3 id="步驟-1-配置模組化的-javascript-環境" tabindex="-1">步驟 1：配置模組化的 JavaScript 環境 <a class="header-anchor" href="#步驟-1-配置模組化的-javascript-環境" aria-label="Permalink to &quot;步驟 1：配置模組化的 JavaScript 環境&quot;">​</a></h3><p>模塊化的 <code>JavaScript</code> 環境可以讓你將代碼拆分為模塊在單一文件中編寫，並從 <code>npm</code> 註冊表中使用包。具體實現取決於現有配置：</p><ul><li><h4 id="已使用-import-語句分割文件" tabindex="-1">已使用 <code>import</code> 語句分割文件 <a class="header-anchor" href="#已使用-import-語句分割文件" aria-label="Permalink to &quot;已使用 `import` 語句分割文件&quot;">​</a></h4><p>請檢查在 <code>JavaScript</code> 代碼中編寫 <code>&lt;div /&gt;</code> 是否會導致語法錯誤。如果報錯，可能需要使用 <code>Babel</code> 轉換代碼，並啟用 <code>Babel React preset</code> 來支持 <code>JSX</code>。</p></li><li><h4 id="沒有用於編譯-javascript-模塊的配置" tabindex="-1">沒有用於編譯 JavaScript 模塊的配置 <a class="header-anchor" href="#沒有用於編譯-javascript-模塊的配置" aria-label="Permalink to &quot;沒有用於編譯 JavaScript 模塊的配置&quot;">​</a></h4><p>請使用 <code>Vite</code> 進行配置。<code>Vite</code> 社區維護了與後端框架（包括 <code>Rails</code>、<code>Django</code> 和 <code>Laravel</code>）的許多集成項目。若後端框架未列出，可按照其指南手動將 <code>Vite</code> 構建集成到後端。</p></li></ul><div class="info custom-block"><p class="custom-block-title">配置有效性檢查</p><ul><li>在項目文件夾中執行：<code>npm install react react-dom</code></li><li>在 <code>JavaScript</code> 主文件（如 <code>index.js</code> 或 <code>main.js</code>）頂部添加代碼，使用 <code>createRoot</code> 清除現有 <code>HTML</code> 並渲染 <code>&lt;h1&gt;Hello, world&lt;/h1&gt;</code>。如果頁面全部內容成功替換為 <code>&quot;Hello, world!&quot;</code>，則代表配置正常。</li></ul></div></li><li><h3 id="步驟-2-在頁面的任何位置渲染-react-元件" tabindex="-1">步驟 2：在頁面的任何位置渲染 React 元件 <a class="header-anchor" href="#步驟-2-在頁面的任何位置渲染-react-元件" aria-label="Permalink to &quot;步驟 2：在頁面的任何位置渲染 React 元件&quot;">​</a></h3><p>實際開發時，你不需要清除現有的全部 <code>HTML</code> 內容，而是要在特定位置渲染 <code>React</code> 組件：</p><ol><li><p>打開 <code>HTML</code> 頁面（或服務端模板），向任意一個標籤添加唯一的 <code>id</code> 屬性（例如：<code>&lt;nav id=&quot;navigation&quot;&gt;&lt;/nav&gt;</code>）。</p></li><li><p>在 <code>JavaScript</code> 中使用 <code>document.getElementById(&#39;navigation&#39;)</code> 查找到該元素。</p></li><li><p>將該 <code>DOM</code> 節點傳遞給 <code>createRoot</code>，並在其中調用 <code>root.render(&lt;NavigationBar/&gt;)</code> 來渲染你的 <code>React</code> 組件。</p></li></ol><ul><li><h4 id="發展路徑" tabindex="-1">發展路徑 <a class="header-anchor" href="#發展路徑" aria-label="Permalink to &quot;發展路徑&quot;">​</a></h4> 通常會從小型交互式組件（如按鈕）開始，然後逐漸“向上移動”，直到最終整個頁面都由 <code>React</code> 構建。屆時建議立即遷移到一個 <code>React</code> 框架以充分利用其優勢。</li></ul></li></ul></li></ul><h2 id="在現有的原生行動應用程式中使用-react-native" tabindex="-1">在現有的原生行動應用程式中使用 React Native <a class="header-anchor" href="#在現有的原生行動應用程式中使用-react-native" aria-label="Permalink to &quot;在現有的原生行動應用程式中使用 React Native&quot;">​</a></h2><p><a href="https://reactnative.dev/" target="_blank" rel="noreferrer">React Native</a> 也可以逐步集成到現有的原生應用中。 如果你已經有一個現有的 <code>Android</code>（Java 或 Kotlin）或 <code>iOS</code>（Objective-C 或 Swift）原生應用，可以按照官方提供的 <a href="https://reactnative.dev/docs/integration-with-existing-apps" target="_blank" rel="noreferrer">指南</a> 將 <code>React Native</code> 添加到其中。</p>',11)])])}const v=a(d,[["render",i]]);export{u as __pageData,v as default};
